/* ---------- Timeline lateral ---------- */

.timeline-aside {
  position: fixed;
  left: var(--space-lg);
  top: 50%;
  transform: translateY(-50%);
  z-index: 90;
  pointer-events: none;
}

.timeline-track {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2.5rem;
  padding: var(--space-lg) 0;
  pointer-events: auto;

/* ---- Grid override for certeza cards ---- */

.events-grid--certeza {
  grid-template-columns: repeat(auto-fill, minmax(min(100%, 22rem), 1fr));
  gap: var(--space-xl);
  align-items: start;
}

/* ---- Shared certeza card structure ---- */

.card-hecho,
.card-opinion,
.card-rumor {
  border-top: none;
  border-left: 4px solid transparent;
  padding: 0;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

/* ---- Certeza indicator bar (top of card) ---- */

.card-certeza-indicator {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-sm) var(--space-lg);
  font-family: var(--font-body);
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

